// MARK: - Token Manager

class TokenManager {
    static let shared = TokenManager()
    
    private let accessTokenKey = "com.app.accessToken"
    private let refreshTokenKey = "com.app.refreshToken"
    
    private init() {}
    
    var accessToken: String? {
        get { KeychainHelper.read(key: accessTokenKey) }
        set {
            if let value = newValue {
                KeychainHelper.save(key: accessTokenKey, value: value)
            } else {
                KeychainHelper.delete(key: accessTokenKey)
            }
        }
    }
    
    var refreshToken: String? {
        get { KeychainHelper.read(key: refreshTokenKey) }
        set {
            if let value = newValue {
                KeychainHelper.save(key: refreshTokenKey, value: value)
            } else {
                KeychainHelper.delete(key: refreshTokenKey)
            }
        }
    }
    
    var isAuthenticated: Bool {
        return accessToken != nil
    }
    
    func saveTokens(_ tokens: AuthTokens) {
        accessToken = tokens.accessToken
        refreshToken = tokens.refreshToken
    }
    
    func clearTokens() {
        accessToken = nil
        refreshToken = nil
    }
}

// MARK: - Keychain Helper

struct KeychainHelper {
    static func save(key: String, value: String) {
        guard let data = value.data(using: .utf8) else { return }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
        
        let attributes: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        SecItemAdd(attributes as CFDictionary, nil)
    }
    
    static func read(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        return String(data: data, encoding: .utf8)
    }
    
    static func delete(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Network Client Protocol

protocol NetworkClientProtocol {
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable?,
        queryParameters: [String: String]?,
        responseType: T.Type
    ) async throws -> T
}

// MARK: - Network Client

class NetworkClient: NetworkClientProtocol {
    static let shared = NetworkClient()
    
    private let session: URLSession
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    private let tokenManager: TokenManager
    private var isRefreshingToken = false
    
    init(
        session: URLSession? = nil,
        tokenManager: TokenManager = .shared
    ) {
        let configuration = URLSessionConfiguration.default
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        configuration.requestCachePolicy = .reloadIgnoringLocalCacheData
        
        self.session = session ?? URLSession(configuration: configuration)
        self.tokenManager = tokenManager
        
        self.decoder = JSONDecoder()
        self.decoder.dateDecodingStrategy = .iso8601
        
        self.encoder = JSONEncoder()
        self.encoder.dateEncodingStrategy = .iso8601
    }
    
    // MARK: - Core Request Method
    
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable? = nil,
        queryParameters: [String: String]? = nil,
        responseType: T.Type
    ) async throws -> T {
        let urlRequest = try buildRequest(
            endpoint: endpoint,
            body: body,
            queryParameters: queryParameters
        )
        
        logRequest(urlRequest)
        
        do {
            let (data, response) = try await session.data(for: urlRequest)
            
            guard let httpResponse = response as? HTTPURLResponse else {
                throw NetworkError.unknown(NSError(domain: "Invalid response", code: -1))
            }
            
            logResponse(httpResponse, data: data)
            
            switch httpResponse.statusCode {
            case 200...299:
                do {
                    let decoded = try decoder.decode(T.self, from: data)
                    return decoded
                } catch {
                    throw NetworkError.decodingError(error)
                }
                
            case 401:
                // Attempt token refresh
                if !isRefreshingToken, endpoint.path != APIEndpoint.refreshToken.path {
                    let refreshed = try await attemptTokenRefresh()
                    if refreshed {
                        return try await request(
                            endpoint: endpoint,
                            body: body,
                            queryParameters: queryParameters,
                            responseType: responseType
                        )
                    }
                }
                tokenManager.clearTokens()
                NotificationCenter.default.post(name: .userDidLogout, object: nil)
                throw NetworkError.unauthorized
                
            case 400...499:
                let errorMessage = parseErrorMessage(from: data)
                throw NetworkError.serverError(
                    statusCode: httpResponse.statusCode,
                    message: errorMessage
                )
                
            case 500...599:
                let errorMessage = parseErrorMessage(from: data)
                throw NetworkError.serverError(
                    statusCode: httpResponse.statusCode,
                    message: errorMessage
                )
                
            default:
                throw NetworkError.serverError(
                    statusCode: httpResponse.statusCode,
                    message: "Unexpected status code"
                )
            }
            
        } catch let error as NetworkError {
            throw error
        } catch let error as URLError {
            switch error.code {
            case .notConnectedToInternet, .networkConnectionLost:
                throw NetworkError.networkUnavailable
            case .timedOut:
                throw NetworkError.timeout
            default:
                throw NetworkError.unknown(error)
            }
        } catch {
            throw NetworkError.unknown(error)
        }
    }
    
    // MARK: - Request Builder
    
    private func buildRequest(
        endpoint: APIEndpoint,
        body: Encodable?,
        queryParameters: [String: String]?
    ) throws -> URLRequest {
        let urlString = NetworkConfiguration.baseURL + endpoint.path
        
        guard var urlComponents = URLComponents(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        if let queryParameters = queryParameters, !queryParameters.isEmpty {
            urlComponents.queryItems = queryParameters.map {
                URLQueryItem(name: $0.key, value: $0.value)
            }
        }
        
        guard let url = urlComponents.url else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = endpoint.method.rawValue
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        // Add auth token if available
        if let accessToken = tokenManager.accessToken {
            request.setValue("Bearer \(accessToken)", forHTTPHeaderField: "Authorization")
        }
        
        // Encode body for POST/PUT requests
        if let body = body, endpoint.method == .post || endpoint.method == .put {
            request.httpBody = try encoder.encode(AnyEncodable(body))
        }
        
        return request
    }
    
    // MARK: - Token Refresh
    
    private func attemptTokenRefresh() async throws -> Bool {
        guard let refreshToken = tokenManager.refreshToken else {
            return false
        }
        
        isRefreshingToken = true
        defer { isRefreshingToken = false }
        
        do {
            let body = ["refresh_token": refreshToken]
            let response: APIResponse<AuthTokens> = try await request(
                endpoint: .refreshToken,
                body: body,
                queryParameters: nil,
                responseType: APIResponse<AuthTokens>.self
            )
            
            if let tokens = response.data {
                tokenManager.saveTokens(tokens)
                return true
            }
            return false
        } catch {
            return false
        }
    }
    
    // MARK: - Error Parsing
    
    private func parseErrorMessage(from data: Data) -> String? {
        if let errorResponse = try? decoder.decode(APIResponse<String>.self, from: data) {
            return errorResponse.message ?? errorResponse.errors?.joined(separator: ", ")
        }
        return String(data: data, encoding: .utf8)
    }
    
    // MARK: - Logging
    
    private func logRequest(_ request: URLRequest) {
        #if DEBUG
        print("🌐 [\(request.httpMethod ?? "?")] \(request.url?.absoluteString ?? "")")
        if let headers = request.allHTTPHeaderFields {
            print("   Headers: \(headers)")
        }
        if let body = request.httpBody, let bodyString = String(data: body, encoding: .utf8) {
            print("   Body: \(bodyString)")
        }
        #endif
    }
    
    private func logResponse(_ response: HTTPURLResponse, data: Data) {
        #if DEBUG
        let emoji = (200...299).contains(response.statusCode) ? "✅" : "❌"
        print("\(emoji) [\(response.statusCode)] \(response.url?.absoluteString ?? "")")
        if let bodyString = String(data: data, encoding: .utf8) {
            let truncated = bodyString.prefix(500)
            print("   Response: \(truncated)")
        }
        #endif
    }
}

// MARK: - AnyEncodable Wrapper

struct AnyEncodable: Encodable {
    private let encodeClosure: (Encoder) throws -> Void
    
    init(_ wrapped: Encodable) {
        self.encodeClosure = { encoder in
            try wrapped.encode(to: encoder)
        }
    }
    
    func encode(to encoder: Encoder) throws {
        try encodeClosure(encoder)
    }
}

// MARK: - Auth Service

protocol AuthServiceProtocol {
    func login(email: String, password: String) async throws -> User
    func register(request: RegisterRequest) async throws -> User
    func logout()
}

class AuthService: AuthServiceProtocol {
    private let networkClient: NetworkClientProtocol
    private let tokenManager: TokenManager
    
    init(
        networkClient: NetworkClientProtocol = NetworkClient.shared,
        tokenManager: TokenManager = .shared
    ) {
        self.networkClient = networkClient
        self.tokenManager = tokenManager
    }
    
    func login(email: String, password: String) async throws -> User {
        let loginRequest = LoginRequest(email: email, password: password)
        
        let response: APIResponse<LoginResponse> = try await networkClient.request(
            endpoint: .login,
            body: loginRequest,
            queryParameters: nil,
            responseType: APIResponse<LoginResponse>.self
        )
        
        guard let loginData = response.data else {
            throw NetworkError.noData
        }
        
        tokenManager.saveTokens(loginData.tokens)
        return loginData.user
    }
    
    func register(request: RegisterRequest) async throws -> User {
        let response: APIResponse<LoginResponse> = try await networkClient.request(
            endpoint: .register,
            body: request,
            queryParameters: nil,
            responseType: APIResponse<LoginResponse>.self
        )
        
        guard let registerData = response.data else {
            throw NetworkError.noData
        }
        
        tokenManager.saveTokens(registerData.tokens)
        return registerData.user
    }
    
    func logout() {
        tokenManager.clearTokens()
        NotificationCenter.default.post(name: .userDidLogout, object: nil)
    }
}

struct LoginResponse: Codable {
    let user: User
    let tokens: AuthTokens
}

// MARK: - User Service

protocol UserServiceProtocol {
    func fetchCurrentUser() async throws -> User
    func fetchUser(id: Int) async throws -> User
    func fetchUsers(page: Int, limit: Int) async throws -> [User]
    func updateProfile(request: UpdateProfileRequest) async throws -> User
}

class UserService: UserServiceProtocol {
    private let networkClient: NetworkClientProtocol
    
    init(networkClient: NetworkClientProtocol = NetworkClient.shared) {
        self.networkClient = networkClient
    }
    
    func fetchCurrentUser() async throws -> User {
        let response: APIResponse<User> = try await networkClient.request(
            endpoint: .userProfile,
            body: nil,
            queryParameters: nil,
            responseType: APIResponse<User>.self
        )
        
        guard let user = response.data else {
            throw NetworkError.noData
        }
        return user
    }
    
    func fetchUser(id: Int) async throws -> User {
        let response: APIResponse<User> = try await networkClient.request(
            endpoint: .userDetail(id: id),
            body: nil,
            queryParameters: nil,
            responseType: APIResponse<User>.self
        )
        
        guard let user = response.data else {
            throw NetworkError.noData
        }
        return user
    }
    
    func fetchUsers(page: Int = 1, limit: Int = 20) async throws -> [User] {
        let queryParams = [
            "page": String(page),
            "limit": String(limit)
        ]
        
        let response: APIResponse<[User]> = try await networkClient.request(
            endpoint: .users,
            body: nil,
            queryParameters: queryParams,
            responseType: APIResponse<[User]>.self
        )
        
        return response.data ?? []
    }
    
    func updateProfile(request: UpdateProfileRequest) async throws -> User {
        let response: APIResponse<User> = try await networkClient.request(
            endpoint: .updateProfile,
            body: request,
            queryParameters: nil,
            responseType: APIResponse<User>.self
        )
        
        guard let user = response.data else {
            throw NetworkError.noData
        }
        return user
    }
}

