// MARK: - Usage Examples (ViewModel)

@MainActor
class AuthViewModel: ObservableObject {
    @Published var currentUser: User?
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var isAuthenticated = false
    
    private let authService: AuthServiceProtocol
    private let userService: UserServiceProtocol
    
    init(
        authService: AuthServiceProtocol = AuthService(),
        userService: UserServiceProtocol = UserService()
    ) {
        self.authService = authService
        self.userService = userService
        self.isAuthenticated = TokenManager.shared.isAuthenticated
    }
    
    func login(email: String, password: String) {
        isLoading = true
        errorMessage = nil
        
        Task {
            do {
                let user = try await authService.login(email: email, password: password)
                self.currentUser = user
                self.isAuthenticated = true
                NotificationCenter.default.post(name: .userDidLogin, object: user)
            } catch let error as NetworkError {
                self.errorMessage = error.errorDescription
            } catch {
                self.errorMessage = error.localizedDescription
            }
            self.isLoading = false
        }
    }
    
    func register(email: String, password: String, firstName: String, lastName: String) {
        isLoading = true
        errorMessage = nil
        
        Task {
            do {
                let request = RegisterRequest(
                    email: email,
                    password: password,
                    firstName: firstName,
                    lastName: lastName
                )
                let user = try await authService.register(request: request)
                self.currentUser = user
                self.isAuthenticated = true
            } catch let error as NetworkError {
                self.errorMessage = error.errorDescription
            } catch {
                self.errorMessage = error.localizedDescription
            }
            self.isLoading = false
        }
    }
    
    func fetchProfile() {
        isLoading = true
        
        Task {
            do {
                let user = try await userService.fetchCurrentUser()
                self.currentUser = user
            } catch let error as NetworkError {
                self.errorMessage = error.errorDescription
            } catch {
                self.errorMessage = error.localizedDescription
            }
            self.isLoading = false
        }
    }
    
    func logout() {
        authService.logout()
        currentUser = nil
        isAuthenticated = false
    }
}

@MainActor
class UsersListViewModel: ObservableObject {
    @Published var users: [User] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    
    private let userService: UserServiceProtocol
    private var currentPage = 1
    
    init(userService: UserServiceProtocol = UserService()) {
        self.userService = userService
    }
    
    func fetchUsers() {
        isLoading = true
        errorMessage = nil
        currentPage = 1
        
        Task {
            do {
                let fetchedUsers = try await userService.fetchUsers(page: currentPage, limit: 20)
                self.users = fetchedUsers
            } catch let error as NetworkError {
                self.errorMessage = error.errorDescription
            } catch {
                self.errorMessage = error.localizedDescription
            }
            self.isLoading = false
        }
    }
    
    func loadMore() {
        guard !isLoading else { return }
        isLoading = true
        currentPage += 1
        
        Task {
            do {
                let moreUsers = try await userService.fetchUsers(page: currentPage, limit: 20)
                self.users.append(contentsOf: moreUsers)
            } catch let error as NetworkError {
                self.errorMessage = error.errorDescription
                self.currentPage -= 1
            } catch {
                self.errorMessage = error.localizedDescription
                self.currentPage -= 1
            }
            self.isLoading = false
        }
    }
}